package com.example.productionapi.controller;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import com.example.productionapi.model.Product;

import java.util.ArrayList;
import java.util.List;
import java.util.Optional;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;

@RestController
@RequestMapping("/api/v1/products")
public class ProductController {

    private static final Logger logger = LoggerFactory.getLogger(ProductController.class);
    private final ConcurrentHashMap<Long, Product> products = new ConcurrentHashMap<>();
    private final AtomicLong productIdCounter = new AtomicLong();

    public ProductController() {
        // Initialize with some dummy data
        Product product1 = new Product(productIdCounter.incrementAndGet(), "Laptop Pro", 1200.00);
        Product product2 = new Product(productIdCounter.incrementAndGet(), "Wireless Mouse", 25.50);
        products.put(product1.getId(), product1);
        products.put(product2.getId(), product2);
        logger.info("Initialized ProductController with {} products.", products.size());
    }

    @GetMapping
    public ResponseEntity<List<Product>> getAllProducts() {
        logger.info("API Call: Received request to get all products.");
        List<Product> productList = new ArrayList<>(products.values());
        logger.info("API Success: Retrieved {} products successfully.", productList.size());
        return ResponseEntity.ok(productList);
    }

    @GetMapping("/{id}")
    public ResponseEntity<Product> getProductById(@PathVariable Long id) {
        logger.debug("API Call: Received request to get product with ID: {}", id);
        Optional<Product> product = Optional.ofNullable(products.get(id));

        if (product.isPresent()) {
            logger.info("API Success: Found product with ID: {}", id);
            return ResponseEntity.ok(product.get());
        } else {
            logger.warn("API Failure: Product with ID: {} not found.", id);
            return ResponseEntity.status(HttpStatus.NOT_FOUND).build();
        }
    }

    @PostMapping
    public ResponseEntity<Product> createProduct(@RequestBody Product product) {
        if (product == null || product.getName() == null || product.getName().trim().isEmpty() || product.getPrice() <= 0) {
            logger.error("API Error: Invalid product data received for creation. Product: {}", product);
            return ResponseEntity.badRequest().build();
        }

        long newId = productIdCounter.incrementAndGet();
        Product newProduct = new Product(newId, product.getName(), product.getPrice());
        products.put(newId, newProduct);
        logger.info("API Success: Created new product with ID: {}. Name: '{}', Price: {}.", newId, newProduct.getName(), newProduct.getPrice());
        return ResponseEntity.status(HttpStatus.CREATED).body(newProduct);
    }

    @PutMapping("/{id}")
    public ResponseEntity<Product> updateProduct(@PathVariable Long id, @RequestBody Product product) {
        logger.debug("API Call: Received request to update product with ID: {}. New data: {}", id, product);
        if (product == null || product.getName() == null || product.getName().trim().isEmpty() || product.getPrice() <= 0) {
            logger.error("API Error: Invalid product data received for update. Product: {}", product);
            return ResponseEntity.badRequest().build();
        }

        if (products.containsKey(id)) {
            Product updatedProduct = new Product(id, product.getName(), product.getPrice());
            products.put(id, updatedProduct);
            logger.info("API Success: Updated product with ID: {}. Name: '{}', Price: {}.", id, updatedProduct.getName(), updatedProduct.getPrice());
            return ResponseEntity.ok(updatedProduct);
        } else {
            logger.warn("API Failure: Attempted to update non-existent product with ID: {}.", id);
            return ResponseEntity.status(HttpStatus.NOT_FOUND).build();
        }
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> deleteProduct(@PathVariable Long id) {
        logger.debug("API Call: Received request to delete product with ID: {}", id);
        if (products.containsKey(id)) {
            products.remove(id);
            logger.info("API Success: Deleted product with ID: {}.", id);
            return ResponseEntity.noContent().build();
        } else {
            logger.warn("API Failure: Attempted to delete non-existent product with ID: {}.", id);
            return ResponseEntity.status(HttpStatus.NOT_FOUND).build();
        }
    }

    @GetMapping("/simulate-error")
    public ResponseEntity<String> simulateError() {
        logger.info("API Call: Received request to simulate an internal server error.");
        try {
            // Simulate an operation that might throw an exception
            int result = 10 / 0; // This will cause an ArithmeticException
            logger.info("This log should not be reached.");
            return ResponseEntity.ok("Result: " + result);
        } catch (ArithmeticException e) {
            logger.error("API Error: An arithmetic exception occurred during error simulation.", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body("An internal server error occurred: " + e.getMessage());
        }
    }
}

// --- src/main/java/com/example/productionapi/model/Product.java ---
package com.example.productionapi.model;

import java.util.Objects;

public class Product {
    private Long id;
    private String name;
    private double price;

    public Product() {
    }

    public Product(Long id, String name, double price) {
        this.id = id;
        this.name = name;
        this.price = price;
    }

    public Long getId() {
        return id;
    }

    public void setId(Long id) {
        this.id = id;
    }

    public String getName() {
        return name;
    }

    public void setName(String name) {
        this.name = name;
    }

    public double getPrice() {
        return price;
    }

    public void setPrice(double price) {
        this.price = price;
    }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (o == null || getClass() != o.getClass()) return false;
        Product product = (Product) o;
        return Double.compare(price, product.price) == 0 && Objects.equals(id, product.id) && Objects.equals(name, product.name);
    }

    @Override
    public int hashCode() {
        return Objects.hash(id, name, price);
    }

    @Override
    public String toString() {
        return "Product{" +
                "id=" + id +
                ", name='" + name + '\'' +
                ", price=" + price +
                '}';
    }
}

